-- Enrichment marathon batch: Jibble, Jimdo, Jiminny, Jira, Jira Service Management, Jitsi Meet, Jitsu, Jitter

-- ── Jibble ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free cloud-based time tracking and attendance software with GPS, facial recognition, and unlimited users.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Kuala Lumpur, Malaysia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Jibble Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jibble review 2026: see how this free time tracking and attendance app uses GPS, facial recognition and biometrics, plus pricing tiers and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jibble is a cloud-based time tracking and workforce attendance platform built around a permanently free core plan, positioning it as one of the most widely adopted 'free forever' time clocks on the market with a self-reported user base above 1.3 million. The company was founded in 2016 by Asim Qureshi and now operates as Jibble Group, headquartered in Kuala Lumpur, Malaysia, with a fully remote, globally distributed team of roughly 50 to 100 people. Jibble Group has raised approximately 7 million dollars in funding across angel and seed rounds from a syndicate of around 39 investors according to Crunchbase, and third-party revenue trackers report annual revenue in the range of 7 to 10.5 million dollars with tens of thousands of customers, including Accenture, OpenWater and PayrollPanda. Technically, Jibble runs as a browser-based web app backed by native mobile apps for iOS and Android, desktop apps for Mac and Windows, a Chrome extension, and integrations that let employees clock in and out directly from Slack or Microsoft Teams. A shared 'kiosk mode' turns any tablet or terminal into a physical time clock for on-site or shift-based teams, and the system supports offline clock-ins that automatically sync once connectivity returns. Its differentiating features center on fraud prevention: AI-powered facial recognition and selfie capture verify that the person clocking in is who they claim to be, GPS location stamping and geofencing confirm they are on-site, and NFC card and PIN options add further verification layers for construction, field service, retail, hospitality, healthcare and logistics employers who need to stop buddy punching. Beyond raw clock-in data, Jibble automates timesheet calculation including breaks and overtime rules, tracks paid time off and leave accrual, offers one-click timesheet approvals, generates exportable XLS and CSV reports and real-time attendance dashboards, and converts billable hours into client invoices, while also connecting to payroll and accounting systems such as QuickBooks, Xero and Deel. Pricing follows a freemium model: the Free plan is unlimited in user count with no credit card required and includes GPS tracking with two geofences, facial recognition, break and overtime tracking, project tracking and unlimited integrations; the Premium plan costs 4.49 dollars per user per month billed annually, after a March 2026 price increase from 2.49 dollars, and adds advanced geofencing plus activity screenshots; the Ultimate plan costs 7.99 dollars per user per month billed annually and unlocks biometric verification on every clock-in, advanced reporting and priority support; and an Enterprise tier offers custom pricing with dedicated onboarding and compliance features for large organizations. Every paid plan except Enterprise includes a 14-day free trial that does not require a credit card. Jibble's target audience skews toward small and mid-sized businesses and deskless, hourly or field-based workforces that need low-cost, high-trust attendance tracking rather than deep project-management functionality, though its project tracking also serves agencies billing hourly clients. In the crowded time-tracking category, Jibble competes most directly with Clockify, which is similarly free-forever and add-on based, Toggl Track, which emphasizes lightweight project time tracking for freelancers, TimeCamp, Deputy and When I Work, which lean harder into shift scheduling for hourly retail staff, and Connecteam, an all-in-one deskless workforce app. Jibble differentiates from these rivals primarily through its unusually generous unlimited-user free tier combined with biometric verification bundled even into that free plan, a combination most competitors reserve for paid tiers, making it a common recommendation for cost-sensitive SMBs and non-profits that still need fraud-resistant attendance data for payroll and compliance.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '83609f1b-4f33-443e-91c3-d41dea40e0aa';

