-- ── Jimdo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$German website builder offering AI-assisted and drag-and-drop editors for small business sites and online stores.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Hamburg, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Jimdo Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jimdo review 2026: explore this Hamburg-based website builder's AI and drag-and-drop editors, e-commerce tools, pricing plans and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jimdo is a German website builder that lets small businesses and freelancers create and manage websites and online stores without coding, offered through two distinct editors: Jimdo Creator, the original drag-and-drop builder, and Jimdo Dolphin, a newer AI-driven builder that generates a starting site from a short questionnaire about the business and then lets the owner refine it visually. The company traces its roots to a farmhouse near Cuxhaven in northern Germany, where Christian Springub and Fridtjof Detzner ran a small web design agency for local businesses starting around 2004; when Matthias Henze joined the team, the trio built their own content management system to speed up client work, which they launched publicly as Jimdo in 2007. Henze serves as CEO, with Springub and Detzner as co-founders. The company grew into a profitable, founder-led business headquartered in Hamburg, Germany, with additional offices in Munich and Tokyo, and today employs roughly 230 to 290 people across Europe, North America and Asia. In June 2015, Jimdo raised 25 million euros from US growth equity firm Spectrum Equity to fund international expansion, localizing the product into 11 languages and 20 currencies; notably, in 2024 the founders repurchased shares from Spectrum and other external investors, returning Jimdo to full founder ownership, an unusual trajectory in a website-builder market otherwise dominated by venture-backed or private-equity-owned players. Architecturally, Jimdo is a fully hosted SaaS platform: customers do not manage servers, and both Creator and Dolphin run in the browser with responsive, mobile-optimized output, integrated SSL, and built-in SEO tools such as automated meta tag suggestions, sitemap generation, and search-engine visibility scoring. E-commerce customers get inventory management, multiple payment gateway support, discount codes and product variants. Pricing is tiered and split between website plans and online store plans, all billed as annual or multi-month commitments rather than pure month-to-month. On the website side, the Play plan is free and limited to 5 pages and 500MB of storage; Start costs 11 dollars a month, includes a free domain for the first year, 5GB storage and up to 10 pages; Grow costs 17 dollars a month with 15GB storage, 50 pages and faster support; and Unlimited costs 45 dollars a month with unlimited storage and pages plus a professional design analysis. On the store side, Basic costs 18 dollars a month with a single shop design, Business costs 26 dollars a month and adds product variants and discounting, and VIP costs 45 dollars a month with premium support and unlimited subpages. Jimdo's core audience is small business owners, solopreneurs, freelancers and local service providers, particularly in the DACH region (Germany, Austria, Switzerland) where it holds strong brand recognition as a homegrown alternative to US platforms, alongside growing English-speaking and international user bases. Its principal competitors are Wix, Squarespace, WordPress.com, GoDaddy Website Builder, Weebly and, for e-commerce specifically, Shopify; Jimdo differentiates through its AI-first Dolphin onboarding flow that produces a usable site in minutes, its European data-hosting posture attractive to privacy-conscious customers, automated SEO tooling aimed at non-technical users, and its unusual status as a profitable, founder-owned company rather than a venture-backed or private-equity-controlled competitor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4a66d624-b348-4934-a255-2bc306fdcf7b';

