INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$GPS Time Tracking and Geofencing$q$, $q$Location-stamped clock-ins with configurable geofences confirm employees are on-site before a shift is logged.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Facial Recognition Verification$q$, $q$AI-based facial recognition and selfie capture prevent buddy punching by confirming employee identity at clock-in.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Automated Timesheets$q$, $q$Hours, breaks and overtime are calculated automatically and routed through one-click manager approval workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Kiosk Mode$q$, $q$Any shared tablet or terminal can act as a physical time clock for on-site or shift-based teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Slack and Microsoft Teams Clock-In$q$, $q$Employees can clock in and out directly from chat tools without opening a separate app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Leave and PTO Management$q$, $q$Tracks paid time off requests, approvals and accrual alongside regular time records.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Payroll Integrations$q$, $q$Native connections to QuickBooks, Xero and Deel move tracked hours directly into payroll processing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Offline Mode$q$, $q$Field and remote employees can clock in without a signal, with entries syncing automatically once reconnected.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Unlimited users on a genuinely free-forever plan with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Biometric facial recognition and geofencing help prevent buddy punching even on the free tier$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Works across web, iOS, Android, Mac, Windows and shared kiosk devices$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Fast setup and simple interface suited to non-technical hourly workforces$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Strong offline support for field, construction and remote teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Advanced reporting, screenshots and priority support require paid Premium or Ultimate tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Premium and Ultimate prices rose sharply in March 2026, roughly 60 to 80 percent higher than before$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Less scheduling and shift-planning depth than dedicated workforce platforms like Deputy or When I Work$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Some users report occasional GPS or facial recognition accuracy issues on older mobile devices$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Support responsiveness can be slower for customers on the free plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Is Jibble actually free to use?$q$, $q$Yes. Jibble's Free plan supports an unlimited number of users with no credit card required, and includes GPS tracking, facial recognition and automated timesheets.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$What does Jibble Premium add over the free plan?$q$, $q$Premium, priced at 4.49 dollars per user per month billed annually, adds features such as advanced geofencing and activity screenshots on top of the free tier's core tracking tools.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Does Jibble work without an internet connection?$q$, $q$Yes. Jibble supports offline clock-ins on mobile, and entries automatically sync to the account once the device reconnects to the internet.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$How does Jibble prevent buddy punching?$q$, $q$Jibble uses AI-powered facial recognition, selfie capture, GPS geofencing and optional NFC card or PIN verification to confirm the person clocking in is the actual employee at an approved location.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Does Jibble integrate with payroll software?$q$, $q$Yes. Jibble connects directly to payroll and accounting platforms including QuickBooks, Xero and Deel to move tracked hours into payroll runs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$What is Jibble's kiosk mode used for?$q$, $q$Kiosk mode turns a shared tablet or terminal into a physical time clock, letting multiple employees clock in and out from one shared device, commonly used in retail, hospitality and construction sites.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Field service and construction attendance$q$, $q$GPS-verified clock-ins and geofencing confirm crews are on the correct job site before hours are logged, reducing payroll disputes.$q$, $q$Construction and field service companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Shift-based retail and hospitality teams$q$, $q$Kiosk mode lets multiple hourly staff clock in on one shared device with facial recognition to prevent buddy punching.$q$, $q$Retail and hospitality managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Remote and distributed agency billing$q$, $q$Project-level time tracking and automated timesheets let agencies convert tracked hours directly into client invoices.$q$, $q$Remote agencies and professional services firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Free$q$, $q$Free$q$, $q$forever$q$, NULL, $q$["Unlimited users","GPS tracking with 2 geofences","Facial recognition verification","Break and overtime tracking","Unlimited integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Premium$q$, $q$$4.49/user/month$q$, $q$billed annually$q$, NULL, $q$["Everything in Free","Advanced geofencing","Activity tracking and screenshots","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Ultimate$q$, $q$$7.99/user/month$q$, $q$billed annually$q$, NULL, $q$["Everything in Premium","Facial recognition on every clock-in","Advanced reporting","Priority support","14-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Dedicated onboarding","Single sign-on","Compliance support","Custom contract terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jibble is a cloud-based time tracking and attendance platform aimed at businesses that need accurate, fraud-resistant clock-in data without paying per-user fees for basic tracking. Founded in 2016 by Asim Qureshi, the company has grown into Jibble Group, a remote-first organization headquartered in Kuala Lumpur, Malaysia, serving well over a million users across industries such as construction, retail, hospitality, healthcare and logistics.$q$, $q$Unlike many time-tracking tools that gate essential features behind a paywall, Jibble offers a genuinely free, unlimited-user plan that includes GPS tracking, facial recognition and automated timesheets. This positions it as an entry point for small businesses and non-profits, while its Premium and Ultimate paid tiers add deeper reporting, screenshots, and advanced verification for larger or compliance-sensitive teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jibble's core strength is identity and location verification. AI-powered facial recognition and selfie capture confirm that the person clocking in is the actual employee, while GPS stamping and geofencing confirm they are physically at an approved work site, addressing the buddy-punching problem common with manual or PIN-only time clocks. A kiosk mode turns any shared tablet into a fixed time clock for on-site teams, and offline mode lets field workers clock in without signal, syncing automatically once back online.$q$, $q$Beyond clock-ins, Jibble automates timesheet calculations including breaks and overtime, manages leave and PTO accrual, and supports one-click approval workflows for managers. Reporting tools export to XLS and CSV, and the platform connects to payroll and accounting systems including QuickBooks, Xero and Deel, letting finance teams move directly from tracked hours to payroll runs without manual re-entry.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83609f1b-4f33-443e-91c3-d41dea40e0aa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jibble uses a freemium model anchored by a Free plan with no user limit, no credit card requirement, and no trial period restrictions — it includes GPS tracking with two geofences, facial recognition, break and overtime tracking, and unlimited integrations. Paid tiers unlock additional depth: Premium is 4.49 dollars per user per month (billed annually) and Ultimate is 7.99 dollars per user per month (billed annually), both up significantly from 2025 pricing after a March 2026 increase.$q$, $q$An Enterprise plan offers custom pricing for large organizations that need dedicated onboarding, single sign-on and compliance support. Every paid plan aside from Enterprise includes a 14-day free trial with no credit card required, making it low-risk for teams to test premium reporting and verification features before committing to a paid seat count.$q$]::text[], 2);
