INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$AI Site Generation (Dolphin)$q$, $q$Answers to a short business questionnaire generate a ready-to-edit starter website with relevant sections and copy suggestions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Drag-and-Drop Editor (Creator)$q$, $q$Manual block-based editing for users who want granular control over layout without AI assistance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Integrated SEO Tools$q$, $q$Automated meta tag suggestions, sitemap generation and a search-visibility score to guide non-technical optimization.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$E-commerce and Online Store$q$, $q$Inventory management, product variants, discount codes and multiple payment gateway support for small online shops.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Mobile-Responsive Design$q$, $q$All templates and AI-generated layouts render responsively across devices by default.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Built-In SSL and Hosting$q$, $q$Fully managed hosting with SSL certificates included on every paid plan, no server management required.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Multi-Language and Multi-Currency Support$q$, $q$Site content and checkout can be localized across roughly 11 languages and 20 currencies for international customers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Custom Domain Included$q$, $q$Paid plans include a free custom domain for the first year, simplifying setup for new site owners.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$AI-assisted Dolphin builder produces a usable site in minutes for non-technical users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Strong built-in SEO guidance aimed specifically at small business owners$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$European-hosted, privacy-conscious alternative to major US website builders$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Founder-owned and profitable, giving it product stability outside typical VC growth pressure$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Free Play plan available with no time limit for very simple sites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$No true month-to-month billing; plans require annual or multi-month commitments$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Fewer third-party app integrations and design templates than Wix or Squarespace$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$E-commerce features are lighter than dedicated platforms like Shopify for larger catalogs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Free Play plan is limited to 5 pages and 500MB of storage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Switching between Creator and Dolphin editors is not seamless if a business outgrows one$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$What is the difference between Jimdo Creator and Jimdo Dolphin?$q$, $q$Creator is Jimdo's original manual drag-and-drop website builder, while Dolphin is a newer AI-assisted builder that generates a starter site from a short questionnaire before letting users refine it visually.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Is Jimdo free to use?$q$, $q$Jimdo offers a free Play plan limited to 5 pages and 500MB of storage; paid plans start at 11 dollars a month for more pages, storage and a free first-year domain.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Can I sell products with Jimdo?$q$, $q$Yes. Jimdo offers dedicated online store plans starting at 18 dollars a month with inventory management, product variants, discount codes and payment gateway support.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Where is Jimdo based?$q$, $q$Jimdo is headquartered in Hamburg, Germany, with additional offices in Munich and Tokyo, and has been fully founder-owned since 2024.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Does Jimdo include SEO tools?$q$, $q$Yes. Jimdo provides built-in SEO guidance including automated meta tag suggestions, sitemap generation and a search-visibility scoring tool aimed at non-technical users.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Can I use my own domain with Jimdo?$q$, $q$Yes. Paid Jimdo plans include a custom domain free for the first year, after which it renews at a standard annual rate.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Local service business websites$q$, $q$Owners with no coding skills use Dolphin's AI questionnaire to launch a professional site with contact details, services and SEO basics in minutes.$q$, $q$Small local businesses and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Small online stores$q$, $q$Store plans handle inventory, product variants and payments for shops with modest catalogs that do not need a dedicated e-commerce platform.$q$, $q$Independent retailers and makers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Portfolio and personal brand sites$q$, $q$Creator's manual drag-and-drop editor suits designers, consultants and creatives who want full layout control.$q$, $q$Freelancers and independent professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Play$q$, $q$Free$q$, $q$forever$q$, NULL, $q$["5 pages","500MB storage","Jimdo subdomain"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Start$q$, $q$$11/month$q$, $q$annual commitment$q$, NULL, $q$["Free domain for 1 year","5GB storage","Up to 10 pages"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Grow$q$, $q$$17/month$q$, $q$annual commitment$q$, NULL, $q$["15GB storage","Up to 50 pages","Faster customer support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$Unlimited$q$, $q$$45/month$q$, $q$annual commitment$q$, NULL, $q$["Unlimited storage and pages","Professional design analysis","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jimdo is a website builder built for people with no coding experience, offering two editing paths: Jimdo Creator, a traditional drag-and-drop builder, and Jimdo Dolphin, an AI-assisted builder that generates a working starter site after users answer a short set of questions about their business. Both products are aimed squarely at small businesses, freelancers and local service providers who need a professional web presence quickly.$q$, $q$Founded in 2007 in Hamburg, Germany, Jimdo has grown into a profitable, founder-owned company with offices in Munich and Tokyo. It occupies a distinct niche among website builders as a European, privacy-conscious alternative to US-based platforms like Wix and Squarespace, with particularly strong brand recognition in Germany, Austria and Switzerland.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jimdo Dolphin's standout feature is its AI onboarding flow, which asks a handful of questions about the business type, style preferences and content needs, then assembles a starter site with relevant sections, imagery and copy suggestions that owners can edit visually. Jimdo Creator, by contrast, gives more granular manual control over layout via drag-and-drop blocks, suited to users who want to build from a blank canvas rather than an AI-generated draft.$q$, $q$Both editors include integrated SEO tools such as automated meta-tag suggestions and search-visibility scoring, mobile-responsive output by default, built-in SSL, and analytics dashboards. E-commerce customers get inventory tracking, multiple payment gateways, discount codes and product variant management, positioning the higher website and store tiers as a lightweight alternative to dedicated e-commerce platforms for small catalogs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jimdo splits pricing into website plans and online store plans, both billed on annual or multi-month terms rather than flexible monthly billing. Website plans run from the free Play tier (5 pages, 500MB storage) through Start (11 dollars a month, free domain for year one), Grow (17 dollars a month, 50 pages) and Unlimited (45 dollars a month, unlimited pages and storage plus a professional design review).$q$, $q$Store plans start at Basic (18 dollars a month, single shop design), step up to Business (26 dollars a month, product variants and discount codes), and top out at VIP (45 dollars a month, premium support and unlimited subpages). A custom domain is included free for the first year on paid plans, after which renewal is billed separately, typically around 20 dollars a year.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4a66d624-b348-4934-a255-2bc306fdcf7b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
