INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$AI Notetaker and Call Recording$q$, $q$Automatically joins and records calls across major video platforms, capturing audio, video and transcripts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Conversation Intelligence$q$, $q$Extracts talk-to-listen ratios, competitor mentions, objection patterns and coaching-worthy moments from every call.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$CRM Logging$q$, $q$Syncs call summaries, notes and next steps automatically into Salesforce, HubSpot and other CRM systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Sales Coaching Tools$q$, $q$Lets managers tag key call moments, build clip libraries and score reps against custom coaching scorecards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Pipeline and Revenue Intelligence$q$, $q$Aggregates conversation data across the pipeline to flag at-risk deals and surface deal-winning behaviors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Competitive Intelligence$q$, $q$Tracks and surfaces competitor mentions across calls to give sales and product teams real-time market visibility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Searchable Call Library$q$, $q$Full-text searchable archive of past calls for onboarding, training and deal handoffs.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Positioned as a more affordable alternative to enterprise-grade revenue intelligence platforms like Gong$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Strong CRM-native workflow that logs notes and next steps automatically$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$SOC 2 Type II certified with GDPR, CCPA and HIPAA compliance for regulated buyers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Free Listener seat option lets non-recording stakeholders view shared call insights at no cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Coaching and clip-library tools are well suited to structured sales enablement programs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Pricing is not published; buyers must go through a sales process to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Annual contracts are typically required, limiting flexibility for smaller or newer teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Recording seats needed for full functionality are priced well above the advertised entry point$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Smaller AI research and feature-release pace compared to category leader Gong$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Multi-year commitments carry lock-in risk if the platform does not deliver expected value$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$What does Jiminny do?$q$, $q$Jiminny is a conversation and revenue intelligence platform that records, transcribes and analyzes sales calls, video meetings and emails to give sales teams coaching insights and pipeline visibility.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$How much does Jiminny cost?$q$, $q$Jiminny does not publish official pricing. Third-party trackers report an Insights seat around 42 dollars per user per month and a Recording seat around 83 dollars per user per month, both typically on annual contracts, alongside a free Listener seat.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Who founded Jiminny?$q$, $q$Jiminny was founded in 2016 by Tom Lavery, who serves as CEO, alongside co-founders including Shelley Lavery.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Is Jiminny SOC 2 certified?$q$, $q$Yes. Jiminny is SOC 2 Type II certified and reports compliance with GDPR, CCPA and HIPAA, along with a 99.9 percent uptime guarantee.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$What is the difference between Jiminny's Insights and Recording seats?$q$, $q$Insights seats provide access to dashboards, analytics and shared recordings but cannot record new calls. Recording seats include full call recording, transcription and coaching capabilities.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$How does Jiminny compare to Gong?$q$, $q$Jiminny targets small and mid-market sales teams with a lower-cost, faster-to-deploy alternative to Gong, which is the larger, more established revenue intelligence platform aimed at enterprise revenue operations teams.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Sales call coaching$q$, $q$Managers review AI-tagged call moments and build clip libraries to coach reps on objection handling and pitch delivery.$q$, $q$Sales managers and enablement teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Pipeline risk visibility$q$, $q$Revenue leaders use aggregated conversation data to spot at-risk deals and competitive threats before they show up in forecast slippage.$q$, $q$Sales and revenue operations leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$CRM-automated call logging$q$, $q$Reps rely on automatic call summaries and CRM syncing to eliminate manual note-taking after every customer call.$q$, $q$Account executives and customer success managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Listener$q$, $q$Free$q$, $q$per seat$q$, NULL, $q$["View shared recordings","Access dashboards","No call recording capability"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Insights$q$, $q$~$42/user/month$q$, $q$annual contract (reported)$q$, NULL, $q$["Full dashboard and analytics access","Shared recording playback","No live call recording"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Recording$q$, $q$~$83/user/month$q$, $q$annual contract (reported)$q$, NULL, $q$["Full call recording and transcription","AI notetaker","Coaching and scorecards","CRM logging"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Custom seat mix","Dedicated support","Tailored security and compliance"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jiminny is a conversation and revenue intelligence platform that records, transcribes and analyzes sales calls, video meetings and emails, turning raw customer conversations into structured coaching and pipeline insights for revenue teams. It joins calls automatically via an AI notetaker, syncs summaries and action items into the CRM, and surfaces trends across a team's full body of conversations.$q$, $q$Founded in 2016 by Tom Lavery and headquartered in London, Jiminny has grown from a UK-focused startup into a company serving B2B sales and customer success teams internationally, backed by roughly 19 million dollars in venture funding including a 16.5 million dollar Series A in 2022 aimed at expanding into the US market.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Jiminny is an AI notetaker that joins calls on platforms like Zoom and Google Meet, records and transcribes the conversation, and extracts structured signals such as talk-to-listen ratio, competitor mentions and objection handling. This data feeds a coaching layer that lets managers tag key moments, build searchable clip libraries for training, and score reps against custom scorecards.$q$, $q$Beyond individual call analysis, Jiminny's revenue intelligence layer rolls conversation data up across the pipeline to flag at-risk deals, highlight recurring objections and competitive mentions, and give leadership visibility into deal health and rep performance without manual reporting. CRM logging automatically syncs notes, next steps and deal updates into systems like Salesforce and HubSpot, reducing administrative work for reps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jiminny does not publish list pricing publicly, selling instead through custom quotes based on a mix of seat types. Reported pricing includes a free Listener seat for viewing shared recordings without recording capability, an Insights seat (around 42 dollars per user per month) for dashboard and analytics access without live call recording, and a Recording seat (around 83 dollars per user per month) that unlocks full recording, transcription and coaching features.$q$, $q$Most plans require annual contracts, with multi-year commitments typically earning discounts of 15 to 20 percent. Prospective customers can trial the platform for 14 days before committing, and an Enterprise tier is available with custom pricing, dedicated support and tailored security requirements for larger sales organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('846a442d-c466-4a1c-ae5e-3ccb660753fb', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Scrum Boards$q$, $q$Sprint planning, burndown charts and velocity tracking purpose-built for teams running agile sprints.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Kanban Boards$q$, $q$Continuous-flow visualization with WIP limits and cumulative flow diagrams for teams without fixed sprints.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Backlog Management$q$, $q$Centralized backlog for prioritizing and grooming upcoming work before it enters a sprint or workflow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Advanced Roadmaps$q$, $q$Cross-team, cross-project timeline planning for coordinating dependencies at scale.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$No-Code Automation$q$, $q$Rule-based automation for status changes, assignments and notifications with plan-based monthly run limits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Atlassian Intelligence and Rovo AI$q$, $q$AI agents that draft issues from natural language, summarize threads and suggest automation rules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Marketplace and Ecosystem Integrations$q$, $q$Native links to Confluence and Bitbucket plus thousands of third-party apps via the Atlassian Marketplace.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Custom Workflows and Permission Schemes$q$, $q$Highly configurable issue types, workflows and permissions to match complex organizational processes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Deep configurability supports both simple and highly complex agile workflows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Free plan covers up to 10 users with real Scrum, Kanban and backlog functionality$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Tight native integration with Confluence, Bitbucket and the wider Atlassian ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Mature automation engine with generous free-tier run allowances$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Backed by a large, well-funded, publicly traded company with a large app marketplace$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Steep learning curve and configuration overhead compared to lighter tools like Linear or Trello$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Per-user-tier pricing model can make cost planning less intuitive than flat per-seat pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Advanced Roadmaps and unlimited automation are locked behind the Premium tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Self-managed Data Center customers must migrate to Cloud ahead of the 2029 end-of-life$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Can feel heavyweight for small teams that only need simple task tracking$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Is Jira free to use?$q$, $q$Yes. Jira's Free plan supports up to 10 users with core issue tracking, Scrum and Kanban boards, a shared backlog, and 2GB of storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Who owns Jira?$q$, $q$Jira is developed by Atlassian, a publicly traded company (NASDAQ: TEAM) founded in 2002 in Sydney, Australia by Mike Cannon-Brookes and Scott Farquhar.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$What is the difference between Jira Standard and Premium?$q$, $q$Standard costs 7.91 dollars per user per month and covers core agile features for up to 300 users, while Premium costs 14.54 dollars per user per month and adds Advanced Roadmaps, unlimited storage and 24/7 support.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Does Jira support Kanban and Scrum?$q$, $q$Yes. Jira natively supports both Scrum boards, with sprints and burndown charts, and Kanban boards, with WIP limits and cumulative flow diagrams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Is Jira Data Center being discontinued?$q$, $q$Atlassian is ending new license sales for Jira Data Center on March 30, 2026, with full end of life on March 28, 2029, pushing customers toward Jira Cloud.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$What are the main alternatives to Jira?$q$, $q$Common Jira alternatives include Asana, Monday.com, ClickUp, Linear, GitHub Issues and Azure DevOps, each varying in configurability, agile depth and ease of use.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Agile software development$q$, $q$Engineering teams run sprints, track velocity and manage backlogs using Scrum boards tightly integrated with source control via Bitbucket.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Cross-team roadmap planning$q$, $q$Product and engineering leadership use Advanced Roadmaps to coordinate dependencies across multiple teams and releases.$q$, $q$Product managers and engineering leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$IT and operations task tracking$q$, $q$Non-engineering teams use Kanban boards and custom workflows to track requests, tasks and approvals outside of software development.$q$, $q$IT and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Free$q$, $q$Free$q$, $q$up to 10 users$q$, NULL, $q$["Scrum and Kanban boards","Backlog management","2GB storage","100 automation runs/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Standard$q$, $q$$7.91/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 300 users","250GB storage","1,700 automation runs/month","Audit logs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Premium$q$, $q$$14.54/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Advanced Roadmaps","Unlimited storage","1,000 automation runs/user/month","24/7 premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Org-wide security controls","Unlimited automation","Centralized admin","Unlimited storage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jira is Atlassian's project and issue tracking software, built originally for software development teams practicing agile methodologies and now widely used by product, IT, marketing and operations teams for planning and tracking work of any kind. It was Atlassian's first product and remains the company's most recognized offering, underpinning workflows for hundreds of thousands of organizations worldwide.$q$, $q$Founded in 2002 in Sydney, Australia by Mike Cannon-Brookes and Scott Farquhar, Atlassian famously bootstrapped its early years without venture funding before going public on NASDAQ in 2015. Jira today ships as a cloud-first SaaS product with configurable workflows, Scrum and Kanban boards, and increasingly deep AI features layered in through Atlassian Intelligence and Rovo.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jira's agile toolset centers on Scrum boards for sprint planning, burndown charts and velocity tracking, and Kanban boards for continuous-flow work with WIP limits and cumulative flow diagrams. A shared backlog lets teams prioritize and groom upcoming work before it enters a sprint, while Advanced Roadmaps helps larger organizations coordinate dependencies across multiple teams and projects on a single timeline.$q$, $q$No-code automation lets teams trigger status changes, assignments and notifications based on configurable rules, with usage allowances that scale from 100 monthly runs on the Free plan up to unlimited on Enterprise. Atlassian Intelligence and Rovo AI agents extend this further, drafting issues from natural-language prompts, summarizing long threads, and suggesting new automation rules, while deep integrations with Confluence, Bitbucket and CI/CD tools like Jenkins keep engineering workflows connected end to end.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jira uses a per-user-tier pricing model. The Free plan supports up to 10 users with core issue tracking, Scrum and Kanban boards, and 2GB of storage; Standard costs 7.91 dollars per user per month for up to 300 users; and Premium costs 14.54 dollars per user per month, adding Advanced Roadmaps, unlimited storage and 24/7 support.$q$, $q$Enterprise pricing is custom, billed only on annual contracts, and adds organization-wide security controls, unlimited automation and centralized administration for large deployments. Atlassian is winding down self-managed Jira Data Center, ending new license sales on March 30, 2026 and reaching end of life on March 28, 2029, which is steering most new and existing customers toward Cloud or Enterprise Cloud plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
