INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44012f42-48cd-4ac2-a9a1-fdf660d20c58', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Incident Management$q$, $q$Aggregates and deduplicates alerts from monitoring tools, then routes on-call notifications via SMS, chat, email or voice.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Change Management$q$, $q$ITIL-style change workflows with automated risk assessment, approval gates and a shared change calendar.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Confluence-Powered Knowledge Base$q$, $q$Shared repository of guides, FAQs and troubleshooting articles for agents and self-service end users.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Customer Service Portal$q$, $q$Configurable self-service portal for submitting and tracking service requests against SLAs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Major Incident Management$q$, $q$Coordinates cross-team response workflows for significant, high-impact outages (Premium and above).$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Configuration Management Database (CMDB)$q$, $q$Tracks IT assets and their relationships to support impact analysis during incidents and changes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$On-Call Scheduling$q$, $q$Opsgenie-derived on-call rotations and escalation policies built natively into JSM's cloud editions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$CI/CD Integrations$q$, $q$Connects to Bitbucket Pipelines, Jenkins and CircleCI so low-risk deployments can bypass manual approval.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Native integration with Jira Software and Confluence suits teams already on the Atlassian ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Significantly lower entry price than enterprise ITSM leaders like ServiceNow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Opsgenie's on-call alerting and incident response are now bundled into higher tiers at no extra cost$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Free tier available for very small IT teams up to 3 agents$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Strong DevOps alignment through CI/CD integrations for automated, low-risk change approvals$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Premium tier more than doubles the per-agent cost over Standard to unlock CMDB and major incident management$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Standalone Opsgenie is being phased out, requiring customers to migrate on Atlassian's timeline$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Less mature enterprise ITSM depth than ServiceNow for very large, complex IT organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Per-agent, volume-tiered pricing can be difficult to forecast as agent counts scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Enterprise tier requires annual contracts and custom sales negotiation, with no public pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$What is Jira Service Management used for?$q$, $q$Jira Service Management is an ITSM platform used for incident management, change management, problem management, service request handling and internal or customer-facing knowledge bases.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Is Jira Service Management the same as Jira Service Desk?$q$, $q$Jira Service Desk was rebranded and substantially rebuilt into Jira Service Management on November 9, 2020, with existing customers migrated automatically at no extra cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$How much does Jira Service Management cost?$q$, $q$JSM has a Free plan for up to 3 agents, a Standard plan around 19 to 24 dollars per agent per month, a Premium plan around 47 to 55 dollars per agent per month, and custom Enterprise pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Is Opsgenie included in Jira Service Management?$q$, $q$Opsgenie's on-call scheduling and alerting capabilities are being integrated natively into JSM's cloud editions, as standalone Opsgenie is being phased out with full end of support in April 2027.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Does Jira Service Management include a CMDB?$q$, $q$Yes, a configuration management database is available starting on the Premium plan, letting teams track IT assets and their relationships during incidents and changes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$What are the main alternatives to Jira Service Management?$q$, $q$Common alternatives include ServiceNow, Zendesk, Freshservice, BMC Helix and ManageEngine ServiceDesk Plus, which vary in enterprise depth, ease of use and pricing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$IT help desk and service requests$q$, $q$IT teams manage employee support tickets, SLAs and a self-service knowledge base through a configurable customer portal.$q$, $q$Internal IT support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$DevOps incident response$q$, $q$Engineering and SRE teams use integrated on-call scheduling and alert routing tied directly to the same Jira instance used for development work.$q$, $q$DevOps and site reliability engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Enterprise change management$q$, $q$Large organizations use ITIL-aligned change workflows with automated risk scoring and CI/CD integration to govern production deployments.$q$, $q$Enterprise IT operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Free$q$, $q$Free$q$, $q$up to 3 agents$q$, NULL, $q$["Service request management","Knowledge base","Basic workflows"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Standard$q$, $q$~$19-24/agent/month$q$, $q$monthly or annual, volume-tiered$q$, NULL, $q$["Incident and problem management","Customer portal","SLA tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Premium$q$, $q$~$47-55/agent/month$q$, $q$monthly or annual, volume-tiered$q$, NULL, $q$["ITIL change workflows","On-call scheduling","CMDB","Major incident management","24/7 support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Org-wide governance","Data residency controls","Unlimited automation","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jira Service Management is Atlassian's IT service management platform, covering incident, change, problem and request management alongside a Confluence-powered knowledge base for internal support teams and end users. It launched in 2013 as the simpler Jira Service Desk before being rebuilt and rebranded to Jira Service Management in November 2020 with deeper ITIL-aligned workflows and Opsgenie integration.$q$, $q$Built on the same underlying platform as Jira Software, JSM lets organizations already using Jira for engineering extend the same instance into IT operations without standing up a separate system, appealing especially to DevOps-oriented teams that want incident response tightly coupled to development workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$JSM's incident management module aggregates alerts from monitoring and logging tools, deduplicates noise, and routes notifications through SMS, email, push, chat and voice calls based on configurable on-call schedules, largely powered by capabilities absorbed from Opsgenie. Change management follows ITIL-style workflows with automated risk scoring, multi-stage approvals, a change calendar, and CI/CD integrations that let low-risk changes skip manual review entirely.$q$, $q$A Confluence-powered knowledge base gives both support agents and self-service end users access to guides, FAQs and troubleshooting articles, reducing repetitive ticket volume, while a configurable customer portal manages service request intake and SLA tracking. Premium and Enterprise tiers add a configuration management database (CMDB) and major incident management for coordinating cross-team responses to significant outages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$JSM offers four tiers. Free is capped at 3 agents and covers core request and knowledge base functionality; Standard runs roughly 19 to 24 dollars per agent per month depending on volume and adds incident and problem management without CMDB or major incident tooling.$q$, $q$Premium runs roughly 47 to 55 dollars per agent per month and unlocks ITIL workflows, integrated on-call scheduling, CMDB, major incident management, AI features and 24/7 support, more than doubling the per-agent price over Standard. Enterprise is custom-priced and billed annually, aimed at large organizations with strict governance and security requirements, typically at deployments of 500 or more agents.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
