INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
