INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7e2a4455-43c7-4157-9b84-0b155a37c0a1', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$No Account Required$q$, $q$Anyone can start or join a meeting on the free public instance without creating an account or installing software.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$End-to-End Encryption$q$, $q$Optional E2EE ensures only meeting participants, not even the server operator, can decrypt audio and video streams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Self-Hosting$q$, $q$Fully open-source Docker and native Linux deployment options give organizations complete control over their infrastructure and data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Screen Sharing and Live Streaming$q$, $q$Built-in screen sharing plus direct YouTube live streaming for webinars and public broadcasts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Breakout Rooms$q$, $q$Meeting hosts can split participants into smaller group sessions for workshops and classes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Cross-Platform Apps$q$, $q$Native apps for Windows, Mac, Linux, iOS and Android alongside full browser support.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Live Captions$q$, $q$Real-time captioning support for accessibility during meetings.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Jitsi as a Service (JaaS)$q$, $q$Managed API and SDK from 8x8 for embedding Jitsi's video infrastructure into third-party applications, billed per monthly active user.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Completely free with no account, download or payment required for the public instance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Fully open source under Apache 2.0, allowing complete self-hosting and code auditing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Optional end-to-end encryption that even the server operator cannot decrypt$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$No hard cap on meeting duration or participant count on self-hosted deployments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Backed by 8x8, a publicly traded communications company, ensuring ongoing maintenance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Call quality can degrade on the free public instance with large groups (roughly 35-plus participants)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Fewer built-in enterprise administration and compliance tools than Zoom or Microsoft Teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Self-hosting requires technical expertise and ongoing server maintenance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Mobile and desktop app polish lags behind well-funded commercial competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$JaaS commercial pricing and recording add-ons are less transparent than flat-rate competitor plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Is Jitsi Meet completely free?$q$, $q$Yes. The public meet.jit.si instance is free to use with no account required, and the underlying software is free and open source for self-hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Who owns Jitsi Meet?$q$, $q$Jitsi Meet is stewarded by 8x8, Inc., a publicly traded cloud communications company that acquired the Jitsi technology and engineering team from Atlassian in October 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Can I self-host Jitsi Meet?$q$, $q$Yes. Jitsi Meet's source code is released under the Apache 2.0 license and can be deployed on your own servers via Docker or native Linux packages for full data control.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Does Jitsi Meet support end-to-end encryption?$q$, $q$Yes. Jitsi Meet offers optional end-to-end encryption that, when enabled, prevents even the server operator from decrypting meeting audio and video.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Do I need an account to join a Jitsi Meet call?$q$, $q$No. Participants can join meetings on the public instance directly from a link in their browser without creating an account.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$What is Jitsi as a Service (JaaS)?$q$, $q$JaaS is 8x8's managed, commercial API and SDK offering built on the open-source Jitsi core, priced per monthly active user starting at 0.35 dollars, aimed at developers embedding video calling into their own products.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Privacy-conscious personal and team calls$q$, $q$Users who want to avoid mandatory accounts and proprietary infrastructure use the free public instance for everyday video calls.$q$, $q$Privacy-conscious individuals and small teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Self-hosted institutional video conferencing$q$, $q$Universities and community organizations deploy self-hosted Jitsi instances to keep meeting data on infrastructure they control.$q$, $q$Universities and community organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Embedded video calling for developers$q$, $q$Product teams use Jitsi as a Service to add video calling to their own applications without building WebRTC infrastructure from scratch.$q$, $q$Developers and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Free Public Instance$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["No account required","Unlimited meeting duration","Screen sharing and live streaming","Cross-platform apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$n/a (infrastructure costs apply)$q$, NULL, $q$["Full source code access (Apache 2.0)","Complete data control","Unlimited customization","Community support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$Jitsi as a Service (JaaS)$q$, $q$From $0.35/MAU$q$, $q$monthly, usage-based$q$, NULL, $q$["Managed hosting and scaling","Free tier up to 25 MAU","API and SDK access","Optional recording at $0.01/minute"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jitsi Meet is a free, open-source video conferencing platform that runs in a web browser without requiring an account or download, and can be fully self-hosted for organizations that want complete control over their video infrastructure and data. It grew out of a 2003 academic VoIP project called SIP Communicator, was rebranded Jitsi in 2011, and has been owned and stewarded by cloud communications provider 8x8 since 2018 after a brief period under Atlassian.$q$, $q$Unlike closed platforms such as Zoom or Google Meet, Jitsi Meet's full source code, including its videobridge, conference focus and web client, is published under the Apache 2.0 license on GitHub, letting anyone audit, modify or self-host the software. This openness, combined with a free public instance at meet.jit.si, made Jitsi a popular privacy-conscious alternative during the pandemic-era surge in video conferencing usage.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jitsi Meet is built on WebRTC with a selective forwarding unit architecture that scales group calls more efficiently than simple peer-to-peer meshes, and supports optional end-to-end encryption that prevents even the server operator from accessing meeting content when enabled. Standard features include screen sharing, YouTube live streaming, virtual backgrounds, breakout rooms, live captions and in-meeting chat.$q$, $q$The platform ships as a free public web service, native desktop and mobile apps for Windows, Mac, Linux, iOS and Android, and self-hostable Docker or native Linux packages for organizations with strict data residency or compliance needs. Developers who want to embed video calling into their own products can use 8x8's Jitsi as a Service (JaaS), a hosted API and SDK layer built on the same open-source core.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Jitsi Meet software is free and open source under the Apache 2.0 license, with no cost for using the public meet.jit.si instance or for self-hosting your own deployment, aside from the infrastructure and technical staff time required to run and maintain it.$q$, $q$For teams that want managed hosting instead of self-hosting, 8x8 offers Jitsi as a Service (JaaS) on a monthly-active-user pricing model starting at 0.35 dollars per MAU with volume discounts, including a free developer tier covering up to 25 monthly active users; cloud call recording is billed separately at 0.01 dollars per minute.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('85b65232-2caf-4969-998f-22b6d54fd447', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
