INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Real-Time Event Ingestion$q$, $q$Captures events from web and mobile SDKs or server-side API calls and routes them to destinations with low latency.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Scriptable Transformations$q$, $q$Configurable JavaScript or YAML-based transformations let teams reshape event data in-flight before it reaches a destination.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Data Warehouse Connectors$q$, $q$Native destinations include BigQuery, Snowflake, Redshift and ClickHouse for downstream analytics and modeling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Events Debugger$q$, $q$Built-in debugging tool for tracing individual events through the pipeline to troubleshoot delivery issues.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Self-Hosting via Docker$q$, $q$Full MIT-licensed codebase can be deployed on customer-controlled infrastructure for cost and compliance reasons.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Unlimited Destinations$q$, $q$Even lower-cost tiers include unlimited destination connections rather than gating by destination count.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Flexible Sync Scheduling$q$, $q$Connector sync frequency ranges from manual and daily on lower tiers up to one-minute intervals on Enterprise.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Genuinely free, unlimited self-hosted open-source tier under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Transparent, usage-based cloud pricing compared to enterprise-negotiated competitors like Segment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Flexible deployment across Cloud, Private Cloud and on-prem for compliance-sensitive teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Developer-friendly configuration via JavaScript and YAML transformations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Backed by Y Combinator and venture funding, supporting continued development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Smaller connector and integration library than category leader Segment$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Self-hosting requires engineering resources to deploy, scale and maintain the infrastructure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Business plan overage pricing (40 dollars per additional million events) can add up for high-volume sites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Smaller company and community than more heavily funded competitors, which may affect long-term roadmap pace$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Enterprise-grade governance and support tooling is less mature than established commercial CDPs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Is Jitsu really free?$q$, $q$Yes. Jitsu's Open Source tier is free forever for self-hosted deployments under the MIT license, and a hosted Free plan on Jitsu Cloud includes 200,000 events per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Who founded Jitsu?$q$, $q$Jitsu was founded in 2019 by Peter Wysinski and Vladimir Klimontovich, who previously built an open-source project called EventNative, and the company went through Y Combinator's Summer 2020 batch.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$How is Jitsu different from Segment?$q$, $q$Jitsu is open source and self-hostable under the MIT license with transparent usage-based pricing, while Segment is a closed-source, enterprise-priced commercial customer data platform owned by Twilio.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Can I self-host Jitsu?$q$, $q$Yes. Jitsu's full codebase is open source and can be deployed via Docker on infrastructure you control, on-prem or in a private cloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$What data warehouses does Jitsu support?$q$, $q$Jitsu connects natively to data warehouses including BigQuery, Snowflake, Redshift and ClickHouse, along with a range of marketing and analytics destinations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$What does the Jitsu Business plan cost?$q$, $q$The Business plan costs 99 dollars per month, including 2 million events monthly, up to 5 active syncs and hourly sync frequency, with additional events billed at 40 dollars per million.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Self-hosted customer data pipelines$q$, $q$Engineering teams deploy Jitsu on their own infrastructure to collect and route event data while keeping raw data under their own control.$q$, $q$Data engineering teams with compliance requirements$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Segment cost replacement$q$, $q$Startups and mid-market companies migrate from Segment to Jitsu Cloud to cut per-event costs while keeping a similar data pipeline architecture.$q$, $q$Startups and mid-market data teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Warehouse-first analytics$q$, $q$Teams route web and app events directly into BigQuery, Snowflake or ClickHouse to power internal analytics and BI tools.$q$, $q$Analytics and BI engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Open Source$q$, $q$Free$q$, $q$forever, self-hosted$q$, NULL, $q$["Full MIT-licensed codebase","Unlimited events (infrastructure-bound)","Community support","Docker deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Free (Cloud)$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["200,000 events/month","Unlimited connectors (manual sync)","Clickhouse UI and API access","Events debugger"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Business$q$, $q$$99/month$q$, $q$monthly$q$, NULL, $q$["2M events/month included","Up to 5 active syncs","Hourly sync frequency","Cloud, Private Cloud or on-prem"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Unlimited monthly active syncs","1-minute sync frequency","Custom event limits","Dedicated deployment support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jitsu is an open-source data ingestion engine positioned as a self-hostable alternative to Segment, letting engineering and data teams collect events from websites and apps and route them in real time to data warehouses, analytics platforms and marketing tools. It was founded in 2019 by Peter Wysinski and Vladimir Klimontovich, went through Y Combinator's Summer 2020 batch, and is based in Berkeley, California.$q$, $q$The project's core differentiator is that its full codebase is released under the MIT license and can be self-hosted via Docker on infrastructure the customer controls, giving teams a genuine free option rather than a limited trial of a closed commercial product, while still offering managed cloud hosting for teams that prefer not to run their own infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jitsu captures events from web and mobile SDKs or direct API calls, applies configurable JavaScript or YAML-based transformations in real time, and routes the resulting data to destinations including BigQuery, Snowflake, Redshift and ClickHouse alongside marketing and analytics tools. A built-in events debugger helps engineering teams troubleshoot pipeline issues without digging through raw logs.$q$, $q$The platform supports both connector-based batch syncs, with configurable sync frequency ranging from daily to as fast as one minute on higher tiers, and lower-latency streaming ingestion for time-sensitive use cases. Deployment flexibility spans Jitsu Cloud, a customer-managed Private Cloud, and fully on-prem installations, letting teams choose the tradeoff between operational simplicity and infrastructure control.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jitsu's Open Source tier is free forever for self-hosted deployments, limited only by the customer's own infrastructure, and includes the full MIT-licensed codebase with community support. A hosted Free plan on Jitsu Cloud includes 200,000 events per month with unlimited connectors on manual sync only.$q$, $q$The Business plan costs 99 dollars per month, raising the included volume to 2 million events monthly (with overage billed at 40 dollars per additional million events), enabling up to 5 active syncs and hourly sync frequency across Cloud, Private Cloud or on-prem deployment. An Enterprise plan offers custom pricing with unlimited monthly active syncs and one-minute sync frequency for large-scale data teams.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('99ecac84-e959-4bdd-9c5f-dac64779d3d2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
