INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Figma Import$q$, $q$Direct import of Figma frames and layers into Jitter while preserving vector shapes, text and component structure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Infinite Canvas Collaboration$q$, $q$Real-time, multiplayer editing on an infinite canvas similar to Figma's collaborative workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Motion Graphics Template Library$q$, $q$Over 300 searchable templates covering social posts, logo reveals, product demos and kinetic typography.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Animation Presets$q$, $q$One-click presets plus curved-path motion, custom vector shape morphing and multi-stop gradient animation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Jitter AI$q$, $q$AI-assisted tools that animate static images, generate design and motion variations, and respond to natural-language prompts to build scenes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$High-Resolution Export$q$, $q$Export up to 4K resolution at 120fps on higher-tier plans, suitable for professional marketing and product use.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Team Libraries$q$, $q$Shared component and template libraries for consistent brand motion assets across a team (Max and above).$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Direct Figma import dramatically speeds up animating existing design assets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Fully browser-based with no software install and strong real-time collaboration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Large, searchable template library covering common social and marketing motion formats$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Jitter AI adds one-click variation generation and prompt-based scene creation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Much gentler learning curve than professional tools like Adobe After Effects$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Free plan is limited to 3 files, 720p export and a visible watermark$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Less deep compositing, effects and control than dedicated professional tools like After Effects$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Team libraries and full collaboration features are gated behind the Max tier and above$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$AI credit allotments on lower tiers may not suit high-volume motion production workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Small team size relative to larger design-tool competitors could affect release pace over time$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$What is Jitter used for?$q$, $q$Jitter is a browser-based motion design tool for creating animations, micro-interactions and short motion graphics, commonly used for social media content, product marketing and UI animation previews.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Can I import Figma designs into Jitter?$q$, $q$Yes. Jitter has a direct Figma import pipeline that preserves vector shapes, text and component structure, letting designers animate existing Figma assets without rebuilding them.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Is Jitter free to use?$q$, $q$Jitter offers a Free plan limited to 3 workspace files, 720p export and 30fps with a watermark; paid Pro, Max and Ultra plans remove these limits and add higher-resolution export and AI features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$What is Jitter AI?$q$, $q$Jitter AI is an AI-assisted layer introduced in 2026 that can animate static images, generate one-click design and motion variations, and respond to natural-language prompts to build or remix animated scenes.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Who founded Jitter?$q$, $q$Jitter was founded in 2020 by Sebastien Robaszkiewicz (CEO) and Etienne Albert (CTO), who previously co-founded the video-editing startup Stupeflix, acquired by GoPro.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$How is Jitter different from Adobe After Effects?$q$, $q$Jitter is a lightweight, browser-based tool focused on fast, template-driven motion graphics and Figma interoperability, while After Effects is a professional desktop application with far deeper compositing and effects capabilities aimed at dedicated motion designers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Social media animation$q$, $q$Marketing teams use Jitter's templates and presets to quickly produce animated social posts and ad creative without a video editor.$q$, $q$Social media and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Product and UI micro-interaction previews$q$, $q$Product designers animate imported Figma components to prototype and present micro-interactions to stakeholders and engineers.$q$, $q$Product and UI/UX designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Brand and logo motion$q$, $q$Freelancers and agencies use Jitter's shape morphing and gradient animation tools to build animated logo reveals and brand assets for clients.$q$, $q$Freelance designers and creative agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Free$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["3 workspace files","720p export","30fps","Watermarked exports"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Pro$q$, $q$~$19/editor/month$q$, $q$billed annually$q$, NULL, $q$["Unlimited files","1080p export at 60fps","No watermark"]$q$::jsonb, 1);
