INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$Ultra$q$, $q$Custom per-editor pricing$q$, $q$billed annually$q$, NULL, $q$["Maximum AI credits","4K export at 120fps","Team libraries"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jitter is a browser-based motion design tool that lets designers and marketers create animations and micro-interactions without traditional video-editing software, often compared to Figma because of its collaborative, infinite-canvas workflow and native Figma import support. It was founded in 2020 by Sebastien Robaszkiewicz and Etienne Albert, who previously co-founded a video-editing startup acquired by GoPro, and the company went through Y Combinator's Winter 2020 batch.$q$, $q$Based near Paris, France, Jitter has stayed intentionally small, with a team of around 7 people focused on a tightly scoped product rather than broad feature sprawl. Its core appeal is speed: designers can import existing Figma layers directly into Jitter, apply animation presets or AI-assisted variations, and export polished motion graphics in minutes rather than hours.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jitter's defining feature is its Figma import pipeline, which preserves vector shapes, text and component structure when bringing designs in from Figma, letting designers animate existing UI or brand assets without rebuilding them. The infinite canvas supports real-time multiplayer collaboration, and the platform ships with over 300 searchable templates spanning social posts, logo reveals, product demos and kinetic typography, plus one-click animation presets, curved-path motion and custom shape morphing.$q$, $q$In 2026, Jitter introduced Jitter AI, which can turn static images into subtly animated video, generate multiple motion variations from a single starting design with one click, and respond to natural-language prompts through a feature branded Superagents to remix templates or build complex animated scenes from scratch, extending the product beyond manual keyframe editing into AI-assisted motion generation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('78d1d55e-3d44-4509-a118-9b5206efa57a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jitter's Free plan is limited to 3 workspace files, 720p export and 30fps with a watermark. The Pro plan, aimed at individuals and freelancers and reported at roughly 19 dollars per editor per month billed annually, removes the watermark and unlocks unlimited files with 1080p export at 60fps.$q$, $q$The Max plan, Jitter's most popular paid tier, targets teams with 4K export at 120fps and fuller collaboration tools, while the Ultra plan is built around AI workflows with the highest monthly allotment of AI credits. An Enterprise plan offers custom pricing with advanced security, SSO, SCIM provisioning and dedicated account management for large organizations, with all paid plans billed annually at a reported 15 percent discount versus monthly billing.$q$]::text[], 2);
